{
  "contents": [{
    "parts": [{
      "text": "Generate exactly 5 real, well-known SaaS companies whose primary website uses a .com domain only. Do not include .io, .in, .ai, or .co domains. Return ONLY a raw JSON array with no markdown formatting, no code fences, no backticks, and no extra text. Exact format: [{\"name\":\"Company Name\",\"domain\":\"company.com\"}]. Use real .com domains you are confident exist."
    }]
  }],
  "generationConfig": {
    "responseMimeType": "application/json"
  }
}

{
  "contents": [{
    "parts": [{
      "text": "Write a cold outreach email. You MUST follow this exact format with no deviation:\n\nSubject: [a short 5-8 word subject line]\n\n[3-sentence email body, casual and direct, referencing their company]\n\nThe email is to {{16.data.data.emails[].first_name}} at {{15.name}}. Always begin your response with 'Subject:' on the first line. Never skip the subject line."
    }]
  }]
}
